// // This module subtracts two 8-bit inputs on the rising edge of the clock when reset is not asserted.
module top_module(
    input clk, rst,
    input [7:0] A, B,
    output reg [7:0] C
);always @(posedge clk) begin
    if(rst) begin
        C <= 0;
    end else begin
        C <= A + B;
    end
end

endmodule
